# OEIS sequence: A397070

from sympy import factorint
from itertools import product
import math
def isok(n):
    sets = []
    for p, e in factorint(n).items():
        if p % 4 == 3:
            if e % 2: return False        # not a Gaussian norm
            sets.append({e//2 + 1})
        elif p == 2:
            sets.append({e + 1})
        else:                              # p == 1 (mod 4)
            sets.append({(a+1)*(e-a+1) for a in range(e+1)})
    return bool(sets) and any(math.prod(c) == 4 for c in product(*sets))
print([n for n in range(2, 600) if isok(n)])

